VALUES
  ('dietitian-moex-07914', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某病患有乳癌家族史，剛被發現左邊乳房有良性纖維組織，醫師已做了切除良性組織之處置，營養師建 議該病患每天應攝取 7 份蔬菜水果，並減少攝取飽和脂肪之食物。病患在下次再回診，見到營養師，表 示：【我現在每天已經吃至少 5 份蔬果，而且也已經不吃肥皮以及高脂肉類】，此為營養教育諮詢理論 中行為改變模式階段的那一個階段？', '["行動期（action）", "準備期（preparation）", "思考期（contemplation）", "思考前期行為（pre-contemplation）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
