  ('dietitian-moex-07916', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '進行情意領域的教學方法與策略中，那幾種教學法比較合適？', '["價值澄清、專家報告、角色扮演", "專家報告、角色扮演、練習教學法", "價值澄清、角色扮演、小組討論", "角色扮演、小組討論、啟發教學法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07917', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某罹病約五年的糖尿病病患，半年前決定加入糖尿病共同照護網進行定期追蹤並接受衛教。但這半年來， 飲食控制仍成效不彰。營養師在策略上應如何開始協助這位病患？', '["介紹相關的書籍以及網站供其參考", "加強醣類計算的概念，以強化飲食控制", "與病患回顧其執行飲食計畫的過程以及狀況，評估可能發生困難之處，並強化患者執行飲食計畫之信心", "增強病患處理併發症之技能與知識"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07918', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某項市售包裝食品每一份能提供 6 公克蛋白質，若製造廠商想標示每份該產品所提供蛋白質之每日營養 素攝取量%，則應標示為多少%？', '["10", "12", "15", "20"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07919', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列有關膳食營養素參考攝取量（Dietary Reference Intakes，DRIs）的敘述，何者正確？', '["當數據不足無法定出足夠攝取量（Adequate Intakes，AIs）時，用實驗結果推算出的營養素量", "RDA是可滿足97-98%的健康人群每天所需要的攝取量", "平均需要量（Estimated Average Requirement，EAR）＝RDA＋2標準差（SD）", "上限攝取量（Tolerable Upper Intake Levels，ULs）＝RDA＋2標準差（SD）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07920', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在行政院衛生署所訂定之國人膳食營養素參考攝取量（DRIs）表中，建議 19-30 歲懷孕婦女葉酸的攝取 量應較未懷孕者增加多少微克？', '["150", "200", "250", "300"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07921', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關鈣質在各生命期之需求量，下列敘述何者正確？', '["鈣質在＞18歲之成人期dietary reference intakes（DRIs）為1000毫克/天", "鈣質在懷孕期之DRIs，在第二期以及第三期，較成人時期增加300毫克/天", "鈣質在＞70歲之老年期之DRIs，較成人時期增加200毫克/天，為1200毫克/天", "鈣質並無上限攝取量（Tolerable upper intake levels, ULs）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07922', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列有關母乳的敘述，何者錯誤？', '["母乳鋅的生物利用率比牛奶低", "一般嬰兒配方奶鋅的生物利用率為31%、豆蛋白配方為14%", "母乳中鋅的含量與母體血中鋅的濃度沒有關係", "母乳中鋅的含量和母親食物鋅的攝取量沒有關係"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
